"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[1866],{83414(t,n,r){r.r(n),r.d(n,{assets:()=>o,contentTitle:()=>a,default:()=>p,frontMatter:()=>u,metadata:()=>e,toc:()=>c});const e=JSON.parse('{"id":"cpp11/future-promise","title":"future\u3001promise\u3001async\u3001packaged_task","description":"C++11 future\u3001promise\u3001async\u3001packaged_task \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/73-future-promise.md","sourceDirName":"cpp11","slug":"/cpp11/73-future-promise","permalink":"/LearnModernCpp/docs/cpp11/73-future-promise","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"future_promise","permalink":"/LearnModernCpp/docs/tags/future-promise"}],"version":"current","sidebarPosition":74,"frontMatter":{"sidebar_position":74,"slug":"73-future-promise","title":"future\u3001promise\u3001async\u3001packaged_task","description":"C++11 future\u3001promise\u3001async\u3001packaged_task \u6559\u5b66\u793a\u4f8b","tags":["cpp11","future_promise"]},"sidebar":"docs","previous":{"title":"\u6761\u4ef6\u53d8\u91cf (condition_variable)","permalink":"/LearnModernCpp/docs/cpp11/72-condition-variable"},"next":{"title":"\u539f\u5b50\u64cd\u4f5c (std::atomic) \u4e0e\u5185\u5b58\u5e8f","permalink":"/LearnModernCpp/docs/cpp11/74-atomic"}}');var s=r(74848),d=r(28453);const u={sidebar_position:74,slug:"73-future-promise",title:"future\u3001promise\u3001async\u3001packaged_task",description:"C++11 future\u3001promise\u3001async\u3001packaged_task \u6559\u5b66\u793a\u4f8b",tags:["cpp11","future_promise"]},a="future\u3001promise\u3001async\u3001packaged_task",o={},c=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function i(t){const n={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,d.R)(),...t.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"futurepromiseasyncpackaged_task",children:"future\u3001promise\u3001async\u3001packaged_task"})}),"\n",(0,s.jsx)(n.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 future\u3001promise\u3001async\u3001packaged_task \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,s.jsx)(n.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-cpp",metastring:'title="cpp11/73_future_promise.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: future\u3001promise\u3001async\u3001packaged_task\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++11\u63d0\u4f9b\u4e86\u9ad8\u7ea7\u5f02\u6b65\u7f16\u7a0b\u5de5\u5177\uff1astd::future \u8868\u793a\u5f02\u6b65\u7ed3\u679c\u7684\u5360\u4f4d\u7b26\uff0c\r\n *           std::promise \u662f\u7ed3\u679c\u7684\u63d0\u4f9b\u8005\uff0cstd::async \u542f\u52a8\u5f02\u6b65\u4efb\u52a1\uff0c\r\n *           std::packaged_task \u5305\u88c5\u53ef\u8c03\u7528\u5bf9\u8c61\u4e3a\u5f02\u6b65\u4efb\u52a1\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u76f4\u63a5\u4f7f\u7528 thread + mutex + condition_variable \u8fdb\u884c\u5f02\u6b65\u7f16\u7a0b\r\n *               \u4ee3\u7801\u590d\u6742\u4e14\u5bb9\u6613\u51fa\u9519\u3002future/promise \u63d0\u4f9b\u4e86\u66f4\u9ad8\u5c42\u6b21\u7684\u62bd\u8c61\uff0c\r\n *               \u7b80\u5316\u4e86\u5f02\u6b65\u7ed3\u679c\u7684\u4f20\u9012\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - std::async: \u6700\u7b80\u5355\u7684\u5f02\u6b65\u6267\u884c\u65b9\u5f0f\uff0c\u8fd4\u56de future\r\n *   - std::future: \u83b7\u53d6\u5f02\u6b65\u64cd\u4f5c\u7684\u7ed3\u679c\uff08\u901a\u8fc7 get() \u963b\u585e\u7b49\u5f85\uff09\r\n *   - std::promise: \u624b\u52a8\u8bbe\u7f6e\u5f02\u6b65\u7ed3\u679c\uff0c\u914d\u5408 future \u4f7f\u7528\r\n *   - std::packaged_task: \u5c06\u53ef\u8c03\u7528\u5bf9\u8c61\u5305\u88c5\u4e3a\u5f02\u6b65\u4efb\u52a1\r\n *   - future::get() \u53ea\u80fd\u8c03\u7528\u4e00\u6b21\uff08\u5982\u9700\u591a\u6b21\u83b7\u53d6\u7528 shared_future\uff09\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <future>\r\n#include <thread>\r\n#include <string>\r\n#include <vector>\r\n#include <numeric>\r\n#include <chrono>\r\n#include <functional>\r\n#include <stdexcept>\r\n#include <mutex>\r\n\r\nstd::mutex g_cout_mtx;\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. std::async \u5f02\u6b65\u8ba1\u7b97\r\n    std::cout << "[1] std::async \u5f02\u6b65\u8ba1\u7b97:\\n";\r\n    {\r\n        // \u5f02\u6b65\u6267\u884c\u4e00\u4e2a\u8017\u65f6\u8ba1\u7b97\r\n        auto fut = std::async(std::launch::async, []() -> int {\r\n            std::this_thread::sleep_for(std::chrono::milliseconds(200));\r\n            return 42;\r\n        });\r\n\r\n        std::cout << "  \u5f02\u6b65\u4efb\u52a1\u5df2\u542f\u52a8\uff0c\u4e3b\u7ebf\u7a0b\u7ee7\u7eed...\\n";\r\n        std::cout << "  \u505a\u4e00\u4e9b\u5176\u4ed6\u5de5\u4f5c...\\n";\r\n\r\n        // get() \u963b\u585e\u7b49\u5f85\u7ed3\u679c\r\n        int result = fut.get();\r\n        std::cout << "  \u5f02\u6b65\u7ed3\u679c: " << result << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 2. async \u8fd4\u56de\u503c\u7c7b\u578b\u63a8\u5bfc\r\n    std::cout << "[2] async \u652f\u6301\u5404\u79cd\u8fd4\u56de\u7c7b\u578b:\\n";\r\n    {\r\n        // \u8fd4\u56de string\r\n        auto fut1 = std::async(std::launch::async, []() -> std::string {\r\n            return "\u5f02\u6b65\u5b57\u7b26\u4e32";\r\n        });\r\n\r\n        // \u8fd4\u56de double\r\n        auto fut2 = std::async(std::launch::async, [](double x) {\r\n            return x * x;\r\n        }, 3.14);\r\n\r\n        std::cout << "  \u5b57\u7b26\u4e32\u7ed3\u679c: " << fut1.get() << std::endl;\r\n        std::cout << "  \u8ba1\u7b97\u7ed3\u679c: " << fut2.get() << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. \u542f\u52a8\u7b56\u7565\r\n    std::cout << "[3] async \u542f\u52a8\u7b56\u7565:\\n";\r\n    {\r\n        // std::launch::async - \u4fdd\u8bc1\u5728\u65b0\u7ebf\u7a0b\u4e2d\u6267\u884c\r\n        auto fut1 = std::async(std::launch::async, []() {\r\n            return std::string("async: \u65b0\u7ebf\u7a0b\u6267\u884c");\r\n        });\r\n\r\n        // std::launch::deferred - \u5ef6\u8fdf\u5230 get()/wait() \u65f6\u5728\u5f53\u524d\u7ebf\u7a0b\u6267\u884c\r\n        auto fut2 = std::async(std::launch::deferred, []() {\r\n            return std::string("deferred: \u5ef6\u8fdf\u6267\u884c");\r\n        });\r\n\r\n        // \u9ed8\u8ba4\u7b56\u7565 - \u7531\u5b9e\u73b0\u51b3\u5b9a\u662f async \u8fd8\u662f deferred\r\n        auto fut3 = std::async([]() {\r\n            return std::string("\u9ed8\u8ba4\u7b56\u7565");\r\n        });\r\n\r\n        std::cout << "  " << fut1.get() << std::endl;\r\n        std::cout << "  " << fut2.get() << " (\u8c03\u7528get\u65f6\u624d\u6267\u884c)" << std::endl;\r\n        std::cout << "  " << fut3.get() << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. promise-future \u901a\u9053\r\n    std::cout << "[4] promise-future \u901a\u9053:\\n";\r\n    {\r\n        std::promise<int> prom;\r\n        std::future<int> fut = prom.get_future();\r\n\r\n        // \u5728\u53e6\u4e00\u4e2a\u7ebf\u7a0b\u4e2d\u8bbe\u7f6e\u7ed3\u679c\r\n        std::thread t([&prom]() {\r\n            std::this_thread::sleep_for(std::chrono::milliseconds(100));\r\n            prom.set_value(100);  // \u8bbe\u7f6e\u7ed3\u679c\r\n        });\r\n\r\n        std::cout << "  \u7b49\u5f85 promise \u7684\u503c...\\n";\r\n        int value = fut.get();  // \u963b\u585e\u7b49\u5f85\r\n        std::cout << "  \u6536\u5230 promise \u7684\u503c: " << value << std::endl;\r\n\r\n        t.join();\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 5. packaged_task\r\n    std::cout << "[5] packaged_task \u5305\u88c5\u53ef\u8c03\u7528\u5bf9\u8c61:\\n";\r\n    {\r\n        // \u521b\u5efa packaged_task\r\n        std::packaged_task<int(int, int)> task([](int a, int b) {\r\n            return a + b;\r\n        });\r\n\r\n        // \u83b7\u53d6\u4e0e\u4e4b\u5173\u8054\u7684 future\r\n        std::future<int> fut = task.get_future();\r\n\r\n        // \u5728\u7ebf\u7a0b\u4e2d\u6267\u884c\u4efb\u52a1\r\n        std::thread t(std::move(task), 10, 20);\r\n\r\n        std::cout << "  packaged_task \u7ed3\u679c: " << fut.get() << std::endl;\r\n        t.join();\r\n    }\r\n    std::cout << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u9ad8\u7ea7\u7528\u6cd5\r\n// ============================================================\r\nvoid advanced_usage() {\r\n    std::cout << "--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. \u5f02\u5e38\u4f20\u9012\r\n    std::cout << "[1] \u901a\u8fc7 future \u4f20\u9012\u5f02\u5e38:\\n";\r\n    {\r\n        // async \u4e2d\u7684\u5f02\u5e38\u4f1a\u88ab\u6355\u83b7\u5e76\u4f20\u9012\u7ed9 future\r\n        auto fut = std::async(std::launch::async, []() -> int {\r\n            throw std::runtime_error("\u5f02\u6b65\u8ba1\u7b97\u51fa\u9519\uff01");\r\n            return 0;\r\n        });\r\n\r\n        try {\r\n            int result = fut.get();  // \u91cd\u65b0\u629b\u51fa\u5f02\u5e38\r\n            (void)result;\r\n        } catch (const std::runtime_error& e) {\r\n            std::cout << "  \u6355\u83b7\u5f02\u6b65\u5f02\u5e38: " << e.what() << std::endl;\r\n        }\r\n\r\n        // promise \u4e5f\u53ef\u4ee5\u8bbe\u7f6e\u5f02\u5e38\r\n        std::promise<int> prom;\r\n        auto fut2 = prom.get_future();\r\n        prom.set_exception(std::make_exception_ptr(\r\n            std::logic_error("promise\u8bbe\u7f6e\u7684\u5f02\u5e38")));\r\n\r\n        try {\r\n            fut2.get();\r\n        } catch (const std::logic_error& e) {\r\n            std::cout << "  \u6355\u83b7promise\u5f02\u5e38: " << e.what() << std::endl;\r\n        }\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 2. future \u72b6\u6001\u67e5\u8be2\r\n    std::cout << "[2] future \u72b6\u6001\u67e5\u8be2:\\n";\r\n    {\r\n        auto fut = std::async(std::launch::async, []() {\r\n            std::this_thread::sleep_for(std::chrono::milliseconds(200));\r\n            return 42;\r\n        });\r\n\r\n        // wait_for \u68c0\u67e5\u662f\u5426\u5b8c\u6210\r\n        auto status = fut.wait_for(std::chrono::milliseconds(50));\r\n        if (status == std::future_status::timeout) {\r\n            std::cout << "  50ms\u540e: \u8fd8\u5728\u8ba1\u7b97\u4e2d...\\n";\r\n        } else if (status == std::future_status::ready) {\r\n            std::cout << "  50ms\u540e: \u5df2\u5b8c\u6210\\n";\r\n        } else if (status == std::future_status::deferred) {\r\n            std::cout << "  \u5ef6\u8fdf\u6267\u884c\\n";\r\n        }\r\n\r\n        // \u7b49\u5f85\u5b8c\u6210\r\n        fut.wait();\r\n        std::cout << "  \u7ed3\u679c: " << fut.get() << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. shared_future\r\n    std::cout << "[3] shared_future (\u591a\u6b21\u83b7\u53d6\u7ed3\u679c):\\n";\r\n    {\r\n        auto fut = std::async(std::launch::async, []() {\r\n            return 42;\r\n        });\r\n\r\n        // \u8f6c\u6362\u4e3a shared_future\r\n        std::shared_future<int> shared = fut.share();\r\n\r\n        // \u591a\u4e2a\u7ebf\u7a0b\u90fd\u53ef\u4ee5 get()\r\n        std::thread t1([shared]() {\r\n            std::lock_guard<std::mutex> lock(g_cout_mtx);\r\n            std::cout << "  \u7ebf\u7a0b1 \u83b7\u53d6: " << shared.get() << std::endl;\r\n        });\r\n\r\n        std::thread t2([shared]() {\r\n            std::lock_guard<std::mutex> lock(g_cout_mtx);\r\n            std::cout << "  \u7ebf\u7a0b2 \u83b7\u53d6: " << shared.get() << std::endl;\r\n        });\r\n\r\n        // \u4e3b\u7ebf\u7a0b\u4e5f\u53ef\u4ee5\u83b7\u53d6\r\n        std::cout << "  \u4e3b\u7ebf\u7a0b\u83b7\u53d6: " << shared.get() << std::endl;\r\n\r\n        t1.join();\r\n        t2.join();\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. \u5e76\u884c\u8ba1\u7b97\u793a\u4f8b\r\n    std::cout << "[4] \u5e76\u884c\u8ba1\u7b97 - \u5206\u6cbb\u6c42\u548c:\\n";\r\n    {\r\n        std::vector<int> data(1000);\r\n        std::iota(data.begin(), data.end(), 1);  // 1, 2, 3, ..., 1000\r\n\r\n        auto partial_sum = [](std::vector<int>::iterator begin,\r\n                              std::vector<int>::iterator end) -> long long {\r\n            return std::accumulate(begin, end, 0LL);\r\n        };\r\n\r\n        auto mid = data.begin() + data.size() / 2;\r\n\r\n        // \u4e24\u4e2a\u5f02\u6b65\u4efb\u52a1\u5e76\u884c\u8ba1\u7b97\r\n        auto fut1 = std::async(std::launch::async, partial_sum, data.begin(), mid);\r\n        auto fut2 = std::async(std::launch::async, partial_sum, mid, data.end());\r\n\r\n        long long total = fut1.get() + fut2.get();\r\n        std::cout << "  1+2+...+1000 = " << total << std::endl;\r\n\r\n        // \u9a8c\u8bc1\r\n        long long expected = 1000LL * 1001 / 2;\r\n        std::cout << "  \u671f\u671b\u7ed3\u679c: " << expected << std::endl;\r\n        std::cout << "  \u6b63\u786e: " << (total == expected ? "\u662f" : "\u5426") << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 5. packaged_task \u5728\u4efb\u52a1\u961f\u5217\u4e2d\u4f7f\u7528\r\n    std::cout << "[5] packaged_task \u4efb\u52a1\u961f\u5217:\\n";\r\n    {\r\n        std::vector<std::packaged_task<int()>> tasks;\r\n        std::vector<std::future<int>> futures;\r\n\r\n        // \u6dfb\u52a0\u4efb\u52a1\u5230\u961f\u5217\r\n        for (int i = 0; i < 5; ++i) {\r\n            std::packaged_task<int()> task([i]() {\r\n                return i * i;\r\n            });\r\n            futures.push_back(task.get_future());\r\n            tasks.push_back(std::move(task));\r\n        }\r\n\r\n        // \u6267\u884c\u6240\u6709\u4efb\u52a1\uff08\u53ef\u4ee5\u5728\u4e0d\u540c\u7ebf\u7a0b\u4e2d\uff09\r\n        std::vector<std::thread> threads;\r\n        for (auto& task : tasks) {\r\n            threads.emplace_back(std::move(task));\r\n        }\r\n\r\n        // \u6536\u96c6\u7ed3\u679c\r\n        std::cout << "  \u4efb\u52a1\u961f\u5217\u7ed3\u679c: ";\r\n        for (auto& f : futures) {\r\n            std::cout << f.get() << " ";\r\n        }\r\n        std::cout << std::endl;\r\n\r\n        for (auto& t : threads) t.join();\r\n    }\r\n    std::cout << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // 1. future::get() \u53ea\u80fd\u8c03\u7528\u4e00\u6b21\r\n    std::cout << "[1] future::get() \u53ea\u80fd\u8c03\u7528\u4e00\u6b21:\\n";\r\n    std::cout << "  // auto fut = std::async(...);\\n";\r\n    std::cout << "  // fut.get();  // \u6b63\u786e\\n";\r\n    std::cout << "  // fut.get();  // \u672a\u5b9a\u4e49\u884c\u4e3a\uff01future\u5df2\u65e0\u6548\\n";\r\n    std::cout << "  // \u9700\u8981\u591a\u6b21\u83b7\u53d6\u7ed3\u679c -> \u4f7f\u7528 shared_future\\n\\n";\r\n\r\n    // 2. async \u8fd4\u56de\u7684 future \u6790\u6784\u65f6\u4f1a\u963b\u585e\r\n    std::cout << "[2] async \u8fd4\u56de\u7684 future \u6790\u6784\u65f6\u4f1a\u963b\u585e\u7b49\u5f85:\\n";\r\n    {\r\n        auto start = std::chrono::steady_clock::now();\r\n        {\r\n            // \u4e0d\u4fdd\u5b58 future\uff0c\u4e34\u65f6\u5bf9\u8c61\u7acb\u5373\u6790\u6784\r\n            std::async(std::launch::async, []() {\r\n                std::this_thread::sleep_for(std::chrono::milliseconds(100));\r\n            });\r\n            // \u6ce8\u610f: \u6790\u6784\u65f6\u4f1a\u963b\u585e\u7b49\u5f85\uff01\r\n        }\r\n        auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(\r\n            std::chrono::steady_clock::now() - start).count();\r\n        std::cout << "  \u672a\u4fdd\u5b58future, \u6790\u6784\u963b\u585e\u4e86: " << elapsed << " ms\\n";\r\n        std::cout << "  \u6559\u8bad: \u59cb\u7ec8\u4fdd\u5b58 async \u8fd4\u56de\u7684 future\\n";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. promise \u5fc5\u987b\u8bbe\u7f6e\u503c\r\n    std::cout << "[3] promise \u5fc5\u987b\u8bbe\u7f6e\u503c\u6216\u5f02\u5e38:\\n";\r\n    std::cout << "  \u5982\u679c promise \u6790\u6784\u65f6\u65e2\u6ca1\u6709 set_value \u4e5f\u6ca1\u6709 set_exception\uff0c\\n";\r\n    std::cout << "  future::get() \u4f1a\u629b\u51fa std::future_error\\n";\r\n    {\r\n        try {\r\n            std::future<int> fut;\r\n            {\r\n                std::promise<int> prom;\r\n                fut = prom.get_future();\r\n            } // promise \u6790\u6784\uff0c\u672a\u8bbe\u7f6e\u503c\r\n\r\n            fut.get();\r\n        } catch (const std::future_error& e) {\r\n            std::cout << "  future_error: " << e.what() << std::endl;\r\n        }\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. deferred \u7b56\u7565\u7684\u9677\u9631\r\n    std::cout << "[4] deferred \u7b56\u7565\u4e0d\u662f\u771f\u6b63\u7684\u5f02\u6b65:\\n";\r\n    std::cout << "  // auto f = std::async(std::launch::deferred, fn);\\n";\r\n    std::cout << "  // // fn \u4e0d\u4f1a\u5728\u65b0\u7ebf\u7a0b\u4e2d\u6267\u884c\uff01\\n";\r\n    std::cout << "  // f.get();  // \u5728\u5f53\u524d\u7ebf\u7a0b\u6267\u884c fn\\n";\r\n    std::cout << "  // wait_for \u603b\u662f\u8fd4\u56de deferred\uff0c\u65e0\u6cd5\u5224\u65ad\u662f\u5426\u5b8c\u6210\\n";\r\n    std::cout << "  // \u9700\u8981\u771f\u6b63\u5f02\u6b65\u65f6\uff0c\u660e\u786e\u6307\u5b9a std::launch::async\\n\\n";\r\n\r\n    // 5. packaged_task \u4e0d\u53ef\u62f7\u8d1d\r\n    std::cout << "[5] packaged_task \u4e0d\u53ef\u62f7\u8d1d\uff0c\u53ea\u80fd\u79fb\u52a8:\\n";\r\n    std::cout << "  // std::packaged_task<int()> t1(fn);\\n";\r\n    std::cout << "  // auto t2 = t1;           // \u7f16\u8bd1\u9519\u8bef\uff01\\n";\r\n    std::cout << "  // auto t2 = std::move(t1); // \u6b63\u786e\\n";\r\n    std::cout << "  // std::thread th(std::move(t1));  // \u5fc5\u987b move \u8fdb thread\\n\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== future / promise / async / packaged_task - C++11 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(n.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:(0,s.jsx)(n.a,{href:"https://en.cppreference.com/w/cpp/thread/future",children:"cppreference: future\u3001promise\u3001async\u3001packaged_task"})}),"\n"]})]})}function p(t={}){const{wrapper:n}={...(0,d.R)(),...t.components};return n?(0,s.jsx)(n,{...t,children:(0,s.jsx)(i,{...t})}):i(t)}},28453(t,n,r){r.d(n,{R:()=>u,x:()=>a});var e=r(96540);const s={},d=e.createContext(s);function u(t){const n=e.useContext(d);return e.useMemo(function(){return"function"==typeof t?t(n):{...n,...t}},[n,t])}function a(t){let n;return n=t.disableParentContext?"function"==typeof t.components?t.components(s):t.components||s:u(t.components),e.createElement(d.Provider,{value:n},t.children)}}}]);